using System.Text.Json;
using System.Text.Json.Serialization;

namespace MorpheusEngine;

// Note: sealing private records is the desired default: it doesn't change affect the open-closed principle while ruling out some potential autogenerated equality comparator bugs.

/// <summary>Thrown when <c>engine_config.json</c> is missing, invalid, or violates the engine contract (fail fast; no silent fallbacks).</summary>
public sealed class EngineConfigurationException : Exception
{
    public EngineConfigurationException(string message)
        : base(message)
    {
    }

    public EngineConfigurationException(string message, Exception innerException)
        : base(message, innerException)
    {
    }
}

/// <summary>Maps each module <c>port_key</c> to its TCP listen port. Ollama is not listed here—it lives on the <c>llm_provider_qwen</c> module as <c>ollama_port</c>.</summary>
public sealed class EnginePortMap
{
    private readonly IReadOnlyDictionary<string, int> _mapping; // Port identifier to int: example: "router" -> 1234

    /// <summary>Keys that must appear under JSON <c>ports</c> (and must not include extra keys).</summary>
    public static readonly string[] RequiredPortKeys = ["router", "llm_provider_qwen", "intent_extractor"]; // TODO: a "generic_llm_provider" module should be required instead of the "llm_provider_qwen". It should be up to the engine to resolve the abstract generic_llm_provider into a concrete llm provider module like llm_provider_qwen.
    /// <summary>Set of <see cref="RequiredPortKeys"/> for fast membership checks (case-insensitive).</summary>
    public static readonly HashSet<string> RequiredPortKeySet = new(RequiredPortKeys, StringComparer.OrdinalIgnoreCase);

    // Constructor restricted to this project only.
    internal EnginePortMap(IReadOnlyDictionary<string, int> mapping)
    {
        _mapping = mapping;
    }

    /// <summary>Returns the configured listen port for a known module <paramref name="portKey"/>.</summary>
    /// <exception cref="EngineConfigurationException">Unknown <paramref name="portKey"/>.</exception>
    public int GetRequiredPort(string portKey) // portKey example: "router", resolves to int.
    {
        if (!_mapping.TryGetValue(portKey, out var port))
        {
            throw new EngineConfigurationException(
                $"Unknown port_key '{portKey}' for listen port lookup. Known keys: {string.Join(", ", RequiredPortKeys)}.");
        }

        return port;
    }

    /// <summary>Whether <paramref name="portKey"/> has a listen port entry (used when validating module rows).</summary>
    public bool HasListenPortForModule(string portKey) => _mapping.ContainsKey(portKey);
}

// TODO: remove running dotnet run development mode pipeline altogether, always use executables instead.
/// <summary>Launch metadata for a module process.</summary>
/// <param name="Artifact">Path to the built executable (often under <c>bin/Debug/...</c>), relative to the repository root unless absolute.</param>
/// <param name="DevProject">Optional path to the <c>.csproj</c> used for <c>dotnet run</c> in development.</param>
public sealed record EngineModuleLaunchInfo(string Artifact, string? DevProject);

/// <summary>One HTTP endpoint exposed by a module.</summary>
/// <param name="Path">URL path on that module, e.g. /health or /intent.</param>
/// <param name="Description">Short label; used by the WPF UI when listing endpoints (see MainWindow).</param>
/// <param name="Method">GET or POST (required in JSON).</param>
/// <param name="RequestContract">Optional logical name for the request body shape (e.g. turn_request); drives sample templates.</param>
/// <param name="BodyTemplate">Optional JSON string template; if omitted, filled from <see cref="EngineContractExamples"/> when <paramref name="RequestContract"/> is set.</param>
public sealed record EngineEndpointInfo(
    string Path, // example: /health, /intent
    string? Description, // Used by MainWindow for combo box / endpoint labels.
    string Method,
    string? RequestContract, // Logical contract id for request JSON shape / examples.
    string? BodyTemplate); // Templates are optional overrides / snippets; contracts stay string ids for JSON flexibility.

// TODO: I'm not convinced with the OllamaPort and DefaultIntentLlmModel fields. Wouldn't it make sense to use inheritence for this class? EngineModuleInfo -> LlmQwenProviderModuleInfo / IntentExtractorModuleInfo ?
public sealed record EngineModuleInfo(
    string PortKey, // stable module id (e.g. router); actual port is in EngineConfiguration.PortMap.
    string DisplayName, // Shown in UI / logs;
    bool Required,
    EngineModuleLaunchInfo LaunchInfo,
    IReadOnlyList<EngineEndpointInfo> Endpoints,
    /// <summary>Ollama listen port; required only for <c>llm_provider_qwen</c>.</summary>
    int? OllamaPort = null,
    /// <summary>Default LLM model for intent extraction; required only for <c>intent_extractor</c>.</summary>
    string? DefaultIntentLlmModel = null);

/// <summary>Loaded engine configuration: repository layout, listen ports, module list, proxy aliases, and intent/Ollama settings derived from module rows.</summary>
public sealed class EngineConfiguration
{
    /// <summary>Repository root containing <c>engine_config.json</c> and typically a <c>dotnet</c> folder.</summary>
    // Q: what's this used for? — Resolving relative artifact paths and choosing the dotnet working directory.
    public string RepositoryRoot { get; }

    public EnginePortMap PortMap { get; }

    public IReadOnlyList<EngineModuleInfo> ModulesInfos { get; }

    // Used to make http messages mention only the generic modules instead of having to rely on specific implementation modules. Ex: llm_provider_qwen becomes just generic_llm_provider and the Router resolves it back to llm_provider_qwen or whichever generic llm module is currently used.
    public IReadOnlyDictionary<string, string> ModuleAliases { get; }

    /// <summary>From the <c>intent_extractor</c> module's <c>default_llm_model</c> in JSON.</summary>
    public string IntentDefaultLlmModel { get; }

    /// <summary>From the <c>llm_provider_qwen</c> module's <c>ollama_port</c> in JSON.</summary>
    public int LlmProviderOllamaListenPort { get; } // Note: I'm not convinced by implementation mentions in this generic class.

    public EngineConfiguration(
        string repositoryRoot,
        EnginePortMap portMap,
        IReadOnlyList<EngineModuleInfo> modulesInfos,
        IReadOnlyDictionary<string, string> moduleAliases,
        string intentDefaultLlmModel,
        int llmProviderOllamaListenPort)
    {
        RepositoryRoot = repositoryRoot;
        PortMap = portMap;
        ModulesInfos = modulesInfos;
        ModuleAliases = moduleAliases;
        IntentDefaultLlmModel = intentDefaultLlmModel;
        LlmProviderOllamaListenPort = llmProviderOllamaListenPort;
    }

    /// <summary>
    /// Resolves a logical proxy target (e.g. <c>generic_llm_provider</c>) to a configured <c>port_key</c> before module lookup.
    /// Keys that are already real <c>port_key</c> values pass through unchanged (not an error—no log spam).
    /// </summary>
    public string ResolveProxyTargetModuleKey(string logicalKey)
    {
        if (string.IsNullOrWhiteSpace(logicalKey))
        {
            Console.WriteLine("[EngineConfig] ResolveProxyTargetModuleKey: empty logicalKey.");
            return logicalKey;
        }

        return ModuleAliases.TryGetValue(logicalKey, out var mapped) && !string.IsNullOrWhiteSpace(mapped)
            ? mapped.Trim()
            : logicalKey;
    }

    /// <inheritdoc cref="EnginePortMap.GetRequiredPort"/>
    public int GetRequiredListenPort(string portKey) => PortMap.GetRequiredPort(portKey);

    /// <summary>
    /// Prefer this over a property: path is derived from <see cref="RepositoryRoot"/> and directory existence.
    /// Example: repository <c>C:\MorpheusEngine</c> with a <c>dotnet</c> subfolder → <c>C:\MorpheusEngine\dotnet</c>;
    /// if <c>dotnet</c> is missing (non-standard layout) → falls back to <see cref="RepositoryRoot"/>.
    /// </summary>
    // Q: in what conditions would dotnetRoot not exist? — Sparse checkouts or running with config at repo root without a dotnet subdir.
    public string GetDotnetRoot()
    {
        var dotnetRoot = Path.Combine(RepositoryRoot, "dotnet");
        return Directory.Exists(dotnetRoot) ? dotnetRoot : RepositoryRoot;
    }

    public EngineModuleInfo? FindModule(string portKey)
    {
        foreach (var module in ModulesInfos)
        {
            if (string.Equals(module.PortKey, portKey, StringComparison.OrdinalIgnoreCase))
            {
                return module;
            }
        }

        return null;
    }

    /// <summary>Finds which module is bound to the given TCP <paramref name="port"/> (listen ports from <see cref="PortMap"/>).</summary>
    public EngineModuleInfo? GetModuleForListeningPort(int port)
    {
        foreach (var module in ModulesInfos)
        {
            if (GetRequiredListenPort(module.PortKey) == port)
            {
                return module;
            }
        }

        return null;
    }

    public EngineEndpointInfo? FindEndpointForPort(int port, string path)
    {
        var normalized = NormalizePath(path);
        var module = GetModuleForListeningPort(port);
        if (module is null)
        {
            return null; // Acceptable to return null in this case: indicates failure to find endpoint.
        }

        foreach (var endpoint in module.Endpoints)
        {
            if (string.Equals(NormalizePath(endpoint.Path), normalized, StringComparison.OrdinalIgnoreCase))
            {
                return endpoint;
            }
        }

        return null;
    }

    public static string NormalizePath(string path)
    {
        if (string.IsNullOrWhiteSpace(path))
        {
            return "/";
        }

        var trimmed = path.Trim();
        return trimmed.StartsWith('/') ? trimmed : "/" + trimmed;
    }
}

// Note: public static class in C# forces a singleton like behaviour.
public static class EngineConfigLoader
{
    #region Nested types
    // DTO: Data transfer object: JSON deserialization shape, not the runtime EngineConfiguration model.

    private sealed class EngineConfigFileDto
    {
        public List<ModuleDto>? Modules { get; set; }

        [JsonPropertyName("module_aliases")]
        public Dictionary<string, string>? ModuleAliases { get; set; }
    }

    private sealed class ModuleDto
    {
        [JsonPropertyName("port_key")]
        public string? PortKey { get; set; }

        [JsonPropertyName("display_name")]
        public string? DisplayName { get; set; }

        public bool? Required { get; set; }
        public ModuleLaunchDto? Launch { get; set; }
        public List<EndpointDto>? Endpoints { get; set; }

        [JsonPropertyName("ollama_port")]
        public int? OllamaPort { get; set; }

        [JsonPropertyName("default_llm_model")]
        public string? DefaultLlmModel { get; set; }
    }

    private sealed class ModuleLaunchDto
    {
        public string? Artifact { get; set; }

        [JsonPropertyName("dev_project")]
        public string? DevProject { get; set; }
    }

    private sealed class EndpointDto
    {
        // Q: why no JsonPropertyName()'s here? — Names match JSON camelCase defaults with PropertyNameCaseInsensitive on serializer.
        public string? Path { get; set; }
        public string? Description { get; set; }
        public string? Method { get; set; }

        [JsonPropertyName("request_contract")]
        public string? RequestContract { get; set; }

        [JsonPropertyName("body_template")]
        public string? BodyTemplate { get; set; }
    }
    #endregion

    #region Private data
    private static readonly JsonSerializerOptions _jsonOptions = new()
    {
        PropertyNameCaseInsensitive = true,
        ReadCommentHandling = JsonCommentHandling.Skip,
        AllowTrailingCommas = true
    };

    private static EngineConfiguration? _cached;

    /// <summary>Protects double-checked initialization of <see cref="_cached"/> together with <see cref="GetConfiguration"/>.</summary>
    // Mutex for the cache: only one thread runs <see cref="LoadConfigurationUncached"/> when cache is cold.
    private static readonly object Sync = new();

    private static IReadOnlyDictionary<string, string> DefaultModuleAliases() =>
        new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase)
        {
            ["generic_llm_provider"] = "llm_provider_qwen"
        };
    #endregion

    #region Public methods
    public static EngineConfiguration GetConfiguration()
    {
        if (_cached is not null)
        {
            return _cached;
        }

        lock (Sync) // Ensures a single thread populates _cached after the null check above (double-checked locking).
        {
            return _cached ??= LoadConfigurationUncached();
        }
    }

    public static EnginePortMap GetPorts() => GetConfiguration().PortMap;
    #endregion

    #region Private methods
    private static EngineConfiguration LoadConfigurationUncached()
    {
        var repositoryRoot = FindRepositoryRoot();
        var path = repositoryRoot is null ? null : Path.Combine(repositoryRoot, "engine_config.json");
        if (repositoryRoot is null || path is null || !File.Exists(path))
        {
            throw new EngineConfigurationException(
                "engine_config.json not found or repository root could not be resolved. Expected the file next to MorpheusEngine sources or under a discovered repo root.");
        }

        string json;
        try
        {
            json = File.ReadAllText(path);
        }
        catch (Exception e)
        {
            throw new EngineConfigurationException($"Failed to read engine_config.json at '{path}'.", e);
        }

        using var doc = JsonDocument.Parse(json, new JsonDocumentOptions { CommentHandling = JsonCommentHandling.Skip });
        var root = doc.RootElement;
        if (!root.TryGetProperty("ports", out var portsElement))
        {
            throw new EngineConfigurationException($"engine_config.json at '{path}' must contain a top-level 'ports' object.");
        }

        var portMap = BuildPortMapFromJson(portsElement, path);

        EngineConfigFileDto? dto;
        try
        {
            dto = JsonSerializer.Deserialize<EngineConfigFileDto>(json, _jsonOptions);
        }
        catch (JsonException e)
        {
            throw new EngineConfigurationException($"Invalid JSON in engine_config.json at '{path}'.", e);
        }

        if (dto?.Modules is null || dto.Modules.Count == 0)
        {
            throw new EngineConfigurationException($"engine_config.json at '{path}' must contain a non-empty 'modules' array.");
        }

        var modules = MergeModules(dto.Modules, portMap, path);
        var moduleAliases = MergeModuleAliases(dto.ModuleAliases, path);
        var intentModel = RequireIntentDefaultModel(modules, path);
        var ollamaPort = RequireLlmProviderOllamaPort(modules, path);

        Console.WriteLine($"Loaded engine configuration from {path}.");
        return new EngineConfiguration(repositoryRoot, portMap, modules, moduleAliases, intentModel, ollamaPort);
    }

    /// <summary>Intentional single call site: kept extracted so <see cref="LoadConfigurationUncached"/> stays readable (CodingStyle documented exception).</summary>
    private static EnginePortMap BuildPortMapFromJson(JsonElement portsEl, string configPath)
    {
        if (portsEl.ValueKind != JsonValueKind.Object)
        {
            throw new EngineConfigurationException($"'ports' in '{configPath}' must be a JSON object.");
        }

        var dict = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var prop in portsEl.EnumerateObject())
        {
            var key = prop.Name.Trim();
            if (!EnginePortMap.RequiredPortKeySet.Contains(key))
            {
                throw new EngineConfigurationException(
                    $"ports: unknown key '{prop.Name}' in '{configPath}'. Allowed keys only: {string.Join(", ", EnginePortMap.RequiredPortKeys)}.");
            }

            if (prop.Value.ValueKind != JsonValueKind.Number || !prop.Value.TryGetInt32(out var port))
            {
                throw new EngineConfigurationException($"ports.{prop.Name} in '{configPath}' must be an integer TCP port.");
            }

            if (port is < 1 or > 65535)
            {
                throw new EngineConfigurationException($"ports.{prop.Name} in '{configPath}' must be between 1 and 65535 (got {port}).");
            }

            dict[key] = port;
        }

        foreach (var required in EnginePortMap.RequiredPortKeys)
        {
            if (!dict.ContainsKey(required))
            {
                throw new EngineConfigurationException(
                    $"ports in '{configPath}' must include '{required}'. Present: {string.Join(", ", dict.Keys)}.");
            }
        }

        Console.WriteLine(
            $"Engine ports: router={dict["router"]}, llm_provider_qwen={dict["llm_provider_qwen"]}, intent_extractor={dict["intent_extractor"]} ({configPath})");
        return new EnginePortMap(dict);
    }

    /// <summary>Intentional single call site: kept extracted for readability (CodingStyle documented exception).</summary>
    private static IReadOnlyList<EngineModuleInfo> MergeModules(
        List<ModuleDto> modulesDto,
        EnginePortMap portMap,
        string path)
    {
        var list = new List<EngineModuleInfo>();
        foreach (var module in modulesDto)
        {
            var portKey = module.PortKey?.Trim();
            if (string.IsNullOrEmpty(portKey))
            {
                throw new EngineConfigurationException($"modules[] entry in '{path}' is missing port_key.");
            }

            if (!portMap.HasListenPortForModule(portKey))
            {
                throw new EngineConfigurationException(
                    $"Module '{portKey}' in '{path}' has no matching entry under ports. Known port keys: {string.Join(", ", EnginePortMap.RequiredPortKeys)}.");
            }

            var launch = MergeLaunch(module.Launch, portKey, path);
            var endpoints = MergeEndpoints(module.Endpoints, portKey, path);

            ValidateModuleScopedOptions(portKey, module.OllamaPort, module.DefaultLlmModel, path);

            list.Add(new EngineModuleInfo(
                portKey,
                string.IsNullOrWhiteSpace(module.DisplayName) ? portKey : module.DisplayName.Trim(),
                module.Required ?? true,
                launch,
                endpoints,
                string.Equals(portKey, "llm_provider_qwen", StringComparison.OrdinalIgnoreCase) ? module.OllamaPort : null,
                string.Equals(portKey, "intent_extractor", StringComparison.OrdinalIgnoreCase)
                    ? module.DefaultLlmModel?.Trim()
                    : null));
        }

        if (list.Count == 0)
        {
            throw new EngineConfigurationException($"No modules could be built from '{path}'.");
        }

        EnsureRequiredModulesPresent(list, path);
        return list;
    }

    private static void ValidateModuleScopedOptions(string portKey, int? ollamaPort, string? defaultLlmModel, string path)
    {
        var isQwen = string.Equals(portKey, "llm_provider_qwen", StringComparison.OrdinalIgnoreCase);
        var isIntent = string.Equals(portKey, "intent_extractor", StringComparison.OrdinalIgnoreCase);

        if (isQwen)
        {
            if (ollamaPort is null or < 1 or > 65535)
            {
                throw new EngineConfigurationException(
                    $"Module 'llm_provider_qwen' in '{path}' must set ollama_port to an integer between 1 and 65535.");
            }
        }
        else if (ollamaPort is not null)
        {
            throw new EngineConfigurationException(
                $"Module '{portKey}' in '{path}' must not set ollama_port (only llm_provider_qwen may).");
        }

        if (isIntent)
        {
            if (string.IsNullOrWhiteSpace(defaultLlmModel))
            {
                throw new EngineConfigurationException(
                    $"Module 'intent_extractor' in '{path}' must set default_llm_model to a non-empty string.");
            }
        }
        else if (!string.IsNullOrWhiteSpace(defaultLlmModel))
        {
            throw new EngineConfigurationException(
                $"Module '{portKey}' in '{path}' must not set default_llm_model (only intent_extractor may).");
        }
    }

    private static void EnsureRequiredModulesPresent(List<EngineModuleInfo> list, string path)
    {
        static bool Has(List<EngineModuleInfo> m, string key) =>
            m.Exists(x => string.Equals(x.PortKey, key, StringComparison.OrdinalIgnoreCase));

        if (!Has(list, "router") || !Has(list, "llm_provider_qwen") || !Has(list, "intent_extractor"))
        {
            throw new EngineConfigurationException(
                $"modules in '{path}' must include router, llm_provider_qwen, and intent_extractor.");
        }
    }

    private static string RequireIntentDefaultModel(IReadOnlyList<EngineModuleInfo> modules, string path)
    {
        var m = modules.FirstOrDefault(x => string.Equals(x.PortKey, "intent_extractor", StringComparison.OrdinalIgnoreCase));
        if (m?.DefaultIntentLlmModel is not { } model || string.IsNullOrWhiteSpace(model))
        {
            throw new EngineConfigurationException($"intent_extractor.default_llm_model missing or empty in '{path}'.");
        }

        Console.WriteLine($"Engine intent default_llm_model={model} ({path})");
        return model;
    }

    private static int RequireLlmProviderOllamaPort(IReadOnlyList<EngineModuleInfo> modules, string path)
    {
        var m = modules.FirstOrDefault(x => string.Equals(x.PortKey, "llm_provider_qwen", StringComparison.OrdinalIgnoreCase));
        if (m?.OllamaPort is not int p)
        {
            throw new EngineConfigurationException($"llm_provider_qwen.ollama_port missing or invalid in '{path}'.");
        }

        Console.WriteLine($"Engine llm_provider_qwen ollama_port={p} ({path})");
        return p;
    }

    /// <summary>Intentional single call site: kept extracted for readability (CodingStyle documented exception).</summary>
    private static EngineModuleLaunchInfo MergeLaunch(ModuleLaunchDto? launch, string portKey, string path)
    {
        if (launch is null || string.IsNullOrWhiteSpace(launch.Artifact))
        {
            throw new EngineConfigurationException($"Module '{portKey}' in '{path}' is missing launch.artifact.");
        }

        return new EngineModuleLaunchInfo(
            launch.Artifact.Trim(),
            string.IsNullOrWhiteSpace(launch.DevProject) ? null : launch.DevProject.Trim());
    }

    /// <summary>Intentional single call site: kept extracted for readability (CodingStyle documented exception).</summary>
    private static IReadOnlyList<EngineEndpointInfo> MergeEndpoints(List<EndpointDto>? endpointsDto, string modulePortKey, string path)
    {
        if (endpointsDto is null)
        {
            throw new EngineConfigurationException($"Module '{modulePortKey}' in '{path}' must declare an endpoints array.");
        }

        var list = new List<EngineEndpointInfo>();
        foreach (var endpoint in endpointsDto)
        {
            var epPath = endpoint.Path?.Trim();
            if (string.IsNullOrEmpty(epPath))
            {
                throw new EngineConfigurationException(
                    $"Module '{modulePortKey}' in '{path}' has an endpoint with missing or empty path.");
            }

            if (string.IsNullOrWhiteSpace(endpoint.Method))
            {
                throw new EngineConfigurationException(
                    $"Module '{modulePortKey}' endpoint '{epPath}' in '{path}' must declare method (GET or POST).");
            }

            var method = endpoint.Method.Trim().ToUpperInvariant();
            if (method is not ("GET" or "POST"))
            {
                throw new EngineConfigurationException(
                    $"Module '{modulePortKey}' endpoint '{epPath}' in '{path}' has invalid method '{endpoint.Method}' (expected GET or POST).");
            }

            var requestContract = string.IsNullOrWhiteSpace(endpoint.RequestContract)
                ? null
                : endpoint.RequestContract.Trim();

            list.Add(new EngineEndpointInfo(
                EngineConfiguration.NormalizePath(epPath),
                string.IsNullOrWhiteSpace(endpoint.Description) ? null : endpoint.Description.Trim(),
                method,
                requestContract,
                string.IsNullOrWhiteSpace(endpoint.BodyTemplate)
                    ? EngineContractExamples.TryGetRequestBodyTemplate(requestContract)
                    : endpoint.BodyTemplate));
        }

        return list;
    }

    private static IReadOnlyDictionary<string, string> MergeModuleAliases(Dictionary<string, string>? fromFile, string path)
    {
        var merged = new Dictionary<string, string>(DefaultModuleAliases(), StringComparer.OrdinalIgnoreCase);
        if (fromFile is not null)
        {
            foreach (var pair in fromFile)
            {
                if (string.IsNullOrWhiteSpace(pair.Key) || string.IsNullOrWhiteSpace(pair.Value))
                {
                    throw new EngineConfigurationException(
                        $"module_aliases in '{path}' contains an entry with empty key or value.");
                }

                merged[pair.Key.Trim()] = pair.Value.Trim();
            }
        }

        Console.WriteLine($"Engine module_aliases: {merged.Count} entries ({path})");
        return merged;
    }
    #endregion

    #region Helpers
    public static string? FindRepositoryRoot()
    {
        return FindRepositoryRoot(new DirectoryInfo(AppContext.BaseDirectory))
            ?? FindRepositoryRoot(new DirectoryInfo(Environment.CurrentDirectory));
    }

    private static string? FindRepositoryRoot(DirectoryInfo? start)
    {
        for (var dir = start; dir is not null; dir = dir.Parent)
        {
            if (File.Exists(Path.Combine(dir.FullName, "engine_config.json")))
            {
                return dir.FullName;
            }

            if (File.Exists(Path.Combine(dir.FullName, "dotnet", "MorpheusEngine.sln")))
            {
                return dir.FullName;
            }

            if (File.Exists(Path.Combine(dir.FullName, "MorpheusEngine.sln")))
            {
                return dir.Parent?.FullName ?? dir.FullName;
            }
        }

        return null;
    }
    #endregion
}
